import json
import boto3
import os
from datetime import datetime
from typing import Dict, Any, List, Optional

sns_client = boto3.client('sns')

def lambda_handler(event: Dict[str, Any], context: Any) -> Dict[str, Any]:
    """
    Lambda function to publish messages to SNS topics.
    
    Event structure:
    {
        "topic_arn": "arn:aws:sns:region:account-id:topic-name",
        "message": "Message content or dict",
        "subject": "Optional subject",
        "notification_type": "email|sms|json|default",
        "attributes": {
            "key": "value"
        },
        "batch_messages": [
            {
                "topic_arn": "...",
                "message": "...",
                "subject": "..."
            }
        ]
    }
    """
    
    try:
        # Handle batch messages if present
        if 'batch_messages' in event:
            return handle_batch_publish(event['batch_messages'])
        
        # Extract event data
        topic_arn = event.get('topic_arn')
        message = event.get('message')
        subject = event.get('subject', '')
        notification_type = event.get('notification_type', 'default')
        message_attributes = event.get('attributes', {})
        
        # Validate required fields
        if not topic_arn:
            return error_response('topic_arn is required', 400)
        
        if not message:
            return error_response('message is required', 400)
        
        # Publish message based on notification type
        response = publish_message(
            topic_arn=topic_arn,
            message=message,
            subject=subject,
            notification_type=notification_type,
            message_attributes=message_attributes
        )
        
        return success_response(response)
        
    except Exception as e:
        return error_response(str(e), 500)


def publish_message(
    topic_arn: str,
    message: Any,
    subject: str = '',
    notification_type: str = 'default',
    message_attributes: Dict[str, str] = None
) -> Dict[str, Any]:
    """
    Publish a message to an SNS topic based on notification type.
    """
    
    # Format message based on notification type
    formatted_message, message_structure = format_message_by_type(
        message, 
        notification_type
    )
    
    # Prepare SNS message attributes
    sns_attributes = prepare_message_attributes(
        message_attributes or {}, 
        notification_type
    )
    
    # Build publish parameters
    publish_params = {
        'TopicArn': topic_arn,
        'Message': formatted_message
    }
    
    # Add subject for email notifications
    if subject and notification_type in ['email', 'default']:
        publish_params['Subject'] = subject[:100]  # SNS subject limit
    
    # Add message structure if needed
    if message_structure:
        publish_params['MessageStructure'] = message_structure
    
    # Add message attributes
    if sns_attributes:
        publish_params['MessageAttributes'] = sns_attributes
    
    # Publish to SNS
    response = sns_client.publish(**publish_params)
    
    return {
        'message_id': response['MessageId'],
        'topic_arn': topic_arn,
        'notification_type': notification_type,
        'timestamp': datetime.utcnow().isoformat()
    }


def format_message_by_type(message: Any, notification_type: str) -> tuple:
    """
    Format message based on notification type.
    Returns (formatted_message, message_structure)
    """
    
    if notification_type == 'json':
        # For JSON notifications, create protocol-specific messages
        if isinstance(message, dict):
            json_message = message
        else:
            json_message = {'default': str(message)}
        
        # Ensure default protocol is present
        if 'default' not in json_message:
            json_message['default'] = json.dumps(json_message)
        
        return json.dumps(json_message), 'json'
    
    elif notification_type == 'email':
        # Format for email notifications
        if isinstance(message, dict):
            formatted = format_email_message(message)
        else:
            formatted = str(message)
        return formatted, None
    
    elif notification_type == 'sms':
        # Format for SMS notifications (keep it short)
        if isinstance(message, dict):
            formatted = message.get('sms', str(message))
        else:
            formatted = str(message)
        # SMS has 140 character limit
        return formatted[:140], None
    
    elif notification_type == 'structured':
        # Create structured message for multiple protocols
        structured_msg = create_structured_message(message)
        return json.dumps(structured_msg), 'json'
    
    else:  # default
        if isinstance(message, dict):
            return json.dumps(message, indent=2), None
        return str(message), None


def format_email_message(message_dict: Dict[str, Any]) -> str:
    """
    Format a dictionary into a readable email message.
    """
    if 'email_body' in message_dict:
        return message_dict['email_body']
    
    # Build formatted message
    lines = []
    
    if 'title' in message_dict:
        lines.append(f"=== {message_dict['title']} ===\n")
    
    if 'body' in message_dict:
        lines.append(message_dict['body'])
        lines.append("")
    
    if 'details' in message_dict:
        lines.append("Details:")
        if isinstance(message_dict['details'], dict):
            for key, value in message_dict['details'].items():
                lines.append(f"  {key}: {value}")
        else:
            lines.append(f"  {message_dict['details']}")
        lines.append("")
    
    if 'footer' in message_dict:
        lines.append(f"\n{message_dict['footer']}")
    
    return "\n".join(lines) if lines else json.dumps(message_dict, indent=2)


def create_structured_message(message: Any) -> Dict[str, str]:
    """
    Create a structured message for multiple protocols.
    """
    if isinstance(message, dict):
        structured = {
            'default': message.get('default', json.dumps(message))
        }
        
        # Email protocol
        if 'email' in message:
            structured['email'] = message['email']
        elif 'body' in message or 'title' in message:
            structured['email'] = format_email_message(message)
        
        # SMS protocol
        if 'sms' in message:
            structured['sms'] = message['sms'][:140]
        
        # HTTP/HTTPS protocols
        if 'http' in message:
            structured['http'] = message['http']
            structured['https'] = message['http']
        
        # SQS protocol
        if 'sqs' in message:
            structured['sqs'] = message['sqs']
        
        # Lambda protocol
        if 'lambda' in message:
            structured['lambda'] = message['lambda']
        
        return structured
    else:
        # Simple message for all protocols
        message_str = str(message)
        return {
            'default': message_str,
            'email': message_str,
            'sms': message_str[:140]
        }


def prepare_message_attributes(
    attributes: Dict[str, str],
    notification_type: str
) -> Dict[str, Dict[str, str]]:
    """
    Prepare SNS message attributes.
    """
    sns_attributes = {}
    
    # Add custom attributes
    for key, value in attributes.items():
        sns_attributes[key] = {
            'DataType': 'String',
            'StringValue': str(value)
        }
    
    # Add notification type as attribute
    sns_attributes['notification_type'] = {
        'DataType': 'String',
        'StringValue': notification_type
    }
    
    # Add timestamp
    sns_attributes['timestamp'] = {
        'DataType': 'String',
        'StringValue': datetime.utcnow().isoformat()
    }
    
    return sns_attributes


def handle_batch_publish(batch_messages: List[Dict[str, Any]]) -> Dict[str, Any]:
    """
    Handle publishing multiple messages in batch.
    """
    results = []
    errors = []
    
    for idx, msg_config in enumerate(batch_messages):
        try:
            topic_arn = msg_config.get('topic_arn')
            message = msg_config.get('message')
            subject = msg_config.get('subject', '')
            notification_type = msg_config.get('notification_type', 'default')
            attributes = msg_config.get('attributes', {})
            
            if not topic_arn or not message:
                errors.append({
                    'index': idx,
                    'error': 'Missing topic_arn or message'
                })
                continue
            
            result = publish_message(
                topic_arn=topic_arn,
                message=message,
                subject=subject,
                notification_type=notification_type,
                message_attributes=attributes
            )
            
            results.append({
                'index': idx,
                'success': True,
                'message_id': result['message_id']
            })
            
        except Exception as e:
            errors.append({
                'index': idx,
                'error': str(e)
            })
    
    return {
        'statusCode': 200 if not errors else 207,  # 207 Multi-Status
        'body': json.dumps({
            'message': 'Batch publish completed',
            'total': len(batch_messages),
            'successful': len(results),
            'failed': len(errors),
            'results': results,
            'errors': errors
        })
    }


def publish_with_filter_policy(
    topic_arn: str,
    message: Any,
    filter_attributes: Dict[str, Any],
    subject: str = ''
) -> Dict[str, Any]:
    """
    Publish message with filter policy attributes for targeted delivery.
    """
    sns_attributes = {}
    
    for key, value in filter_attributes.items():
        # Determine data type
        if isinstance(value, (int, float)):
            sns_attributes[key] = {
                'DataType': 'Number',
                'StringValue': str(value)
            }
        elif isinstance(value, list):
            sns_attributes[key] = {
                'DataType': 'String.Array',
                'StringValue': json.dumps(value)
            }
        else:
            sns_attributes[key] = {
                'DataType': 'String',
                'StringValue': str(value)
            }
    
    publish_params = {
        'TopicArn': topic_arn,
        'Message': json.dumps(message) if isinstance(message, dict) else str(message),
        'MessageAttributes': sns_attributes
    }
    
    if subject:
        publish_params['Subject'] = subject[:100]
    
    response = sns_client.publish(**publish_params)
    
    return {
        'message_id': response['MessageId'],
        'topic_arn': topic_arn
    }


def publish_fifo_message(
    topic_arn: str,
    message: Any,
    message_group_id: str,
    message_deduplication_id: Optional[str] = None,
    subject: str = ''
) -> Dict[str, Any]:
    """
    Publish message to FIFO SNS topic.
    """
    publish_params = {
        'TopicArn': topic_arn,
        'Message': json.dumps(message) if isinstance(message, dict) else str(message),
        'MessageGroupId': message_group_id
    }
    
    if message_deduplication_id:
        publish_params['MessageDeduplicationId'] = message_deduplication_id
    
    if subject:
        publish_params['Subject'] = subject[:100]
    
    response = sns_client.publish(**publish_params)
    
    return {
        'message_id': response['MessageId'],
        'sequence_number': response.get('SequenceNumber'),
        'topic_arn': topic_arn
    }


def success_response(data: Dict[str, Any]) -> Dict[str, Any]:
    """
    Return a successful response.
    """
    return {
        'statusCode': 200,
        'body': json.dumps({
            'success': True,
            'data': data
        })
    }


def error_response(error_message: str, status_code: int = 400) -> Dict[str, Any]:
    """
    Return an error response.
    """
    return {
        'statusCode': status_code,
        'body': json.dumps({
            'success': False,
            'error': error_message
        })
    }